(function(global){
  const MM_TO_PT=72/25.4;
  function binFromDataUrl(dataUrl){const i=dataUrl.indexOf(',');return atob(dataUrl.slice(i+1));}
  class jsPDF{
    constructor(opts={}){this.orientation=opts.orientation||'portrait';this.unit=opts.unit||'mm';this.format=opts.format||'a4';this.pageW=this.orientation==='landscape'?841.89:595.28;this.pageH=this.orientation==='landscape'?595.28:841.89;this.pages=[[]];}
    _u(v){return this.unit==='mm'?v*MM_TO_PT:v}
    addImage(dataUrl,type,x,y,w,h){this.pages[this.pages.length-1].push({kind:'image',data:binFromDataUrl(dataUrl),x:this._u(x),y:this._u(y),w:this._u(w),h:this._u(h)});return this}
    addPage(){this.pages.push([]);return this}
    save(name='document.pdf'){const blob=this.output('blob');const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=name;document.body.appendChild(a);a.click();setTimeout(()=>{URL.revokeObjectURL(a.href);a.remove()},1200)}
    output(type='blob'){
      const objects=[]; const add=o=>{objects.push(o);return objects.length}; const pageIds=[];
      this.pages.forEach(page=>{
        const xobjs=[]; let content='';
        page.forEach((it,idx)=>{const imgId=add(`<< /Type /XObject /Subtype /Image /Width 1 /Height 1 /ColorSpace /DeviceRGB /BitsPerComponent 8 /Filter /DCTDecode /Length ${it.data.length} >>\nstream\n${it.data}\nendstream`);const name='Im'+idx;xobjs.push(`/${name} ${imgId} 0 R`);const y=this.pageH-it.y-it.h;content+=`q\n${it.w.toFixed(2)} 0 0 ${it.h.toFixed(2)} ${it.x.toFixed(2)} ${y.toFixed(2)} cm\n/${name} Do\nQ\n`;});
        const contId=add(`<< /Length ${content.length} >>\nstream\n${content}endstream`);
        const pageId=add(`<< /Type /Page /Parent 0 0 R /MediaBox [0 0 ${this.pageW} ${this.pageH}] /Resources << /XObject << ${xobjs.join(' ')} >> >> /Contents ${contId} 0 R >>`); pageIds.push(pageId);
      });
      const pagesId=add(''); const catalogId=add(`<< /Type /Catalog /Pages ${pagesId} 0 R >>`);
      objects[pagesId-1]=`<< /Type /Pages /Kids [${pageIds.map(id=>id+' 0 R').join(' ')}] /Count ${pageIds.length} >>`;
      for(let i=0;i<objects.length;i++)objects[i]=objects[i].replace('/Parent 0 0 R',`/Parent ${pagesId} 0 R`);
      let pdf='%PDF-1.4\n'; const offsets=[0];
      objects.forEach((o,i)=>{offsets.push(pdf.length);pdf+=`${i+1} 0 obj\n${o}\nendobj\n`;});
      const xref=pdf.length; pdf+=`xref\n0 ${objects.length+1}\n0000000000 65535 f \n`; for(let i=1;i<offsets.length;i++)pdf+=String(offsets[i]).padStart(10,'0')+' 00000 n \n'; pdf+=`trailer << /Size ${objects.length+1} /Root ${catalogId} 0 R >>\nstartxref\n${xref}\n%%EOF`;
      return new Blob([pdf],{type:'application/pdf'});
    }
  }
  global.jspdf={jsPDF};
})(window);
